{"code": "import json
import pandas as pd

# Read the file path from storage
result_file_path = locals()['var_functions.query_db:22']

# Load the breast cancer clinical data
with open(result_file_path, 'r') as f:
    breast_cancer_data = json.load(f)

print(f"Successfully loaded {len(breast_cancer_data)} breast cancer records")
print(f"Sample record: {breast_cancer_data[0]}")

# Extract patient barcodes from Patient_description
def extract_barcode(description):
    if 'TCGA-' in description:
        parts = description.split()
        for part in parts:
            if part.startswith('TCGA-'):
                return part.rstrip(',')
    return None

# Process clinical data
clinical_records = []
for record in breast_cancer_data:
    barcode = extract_barcode(record.get('Patient_description', ''))
    histological_type = record.get('histological_type', 'Unknown')
    if barcode and histological_type and histological_type != 'Unknown':
        clinical_records.append({
            'ParticipantBarcode': barcode,
            'histological_type': histological_type
        })

print(f"\nProcessed {len(clinical_records)} valid clinical records with barcodes")
print(f"Sample processed record: {clinical_records[0] if clinical_records else 'None'}")"}

